 */
export function indent(code: string, spaces: number): string {
  const prefix = ' '.repeat(spaces)
  return code
    .split('\n')
    .map((line) => (line.trim() === '' ? '' : `${prefix}${line}`))
    .join('\n')
}

/**
 * Renders a TypeScript interface declaration with the given field lines.
 */
export function renderInterface(name: string, fields: string[]): string {
  if (fields.length === 0) {
    return `export interface ${name} {}`
  }
  return `export interface ${name} {\n${fields.map((f) => `  ${f}`).join('\n')}\n}`
}

