 * Converts a PascalCase model name to a kebab-case REST URL path segment.
 *
 * Examples: `"UserProfile"` → `"user-profile"`, `"Post"` → `"post"`
 */
export function toUrlPath(modelName: string): string {
  return modelName.replace(/([A-Z])/g, (char, _, offset) => (offset > 0 ? '-' : '') + char.toLowerCase())
}

