 * Converts a PascalCase name to camelCase for use as a property name.
 *
 * Examples: `"User"` → `"user"`, `"BlogPost"` → `"blogPost"`
 */
export function toCamelCase(name: string): string {
  return name.charAt(0).toLowerCase() + name.slice(1)
}

