import { mkdir, rm, writeFile } from 'node:fs/promises'
import path from 'node:path'

import type { DMMF, GeneratorOptions } from '@prisma/generator-helper'

import { indent, renderInterface, toCamelCase, toUrlPath } from './template'

const PRISMA_TYPE_TO_TS: Record<string, string> = {
  String: 'string',
  Boolean: 'boolean',
  Int: 'number',
  Float: 'number',
  BigInt: 'bigint',
  DateTime: 'Date',
  Bytes: 'Buffer',
  Decimal: 'number',
  Json: 'unknown',
}

function fieldToTsType(field: DMMF.Field): string {
  const baseType = field.kind === 'enum' ? field.type : (PRISMA_TYPE_TO_TS[field.type] ?? 'unknown')
  if (field.isList) {
    return field.isRequired ? `${baseType}[]` : `${baseType}[] | null`
  }
  return field.isRequired ? baseType : `${baseType} | null`
}

function generateModelInterface(model: DMMF.Model): string {
  const fields = model.fields
    .filter((f) => f.kind !== 'object')
    .map((f) => `${f.name}: ${fieldToTsType(f)}`)
  return renderInterface(model.name, fields)
}

function generateCreateInput(model: DMMF.Model): string {
  const fields = model.fields
    .filter((f) => f.kind !== 'object' && !f.isReadOnly && !f.isGenerated && !f.isUpdatedAt)
    .map((f) => {
      const optional = !f.isRequired || f.hasDefaultValue ? '?' : ''
      return `${f.name}${optional}: ${fieldToTsType(f)}`
    })
  return renderInterface(`${model.name}CreateInput`, fields)
}

function generateUpdateInput(model: DMMF.Model): string {
  const fields = model.fields
    .filter((f) => f.kind !== 'object' && !f.isReadOnly && !f.isId && !f.isGenerated && !f.isUpdatedAt)
    .map((f) => `${f.name}?: ${fieldToTsType(f)}`)
  return renderInterface(`${model.name}UpdateInput`, fields)
}

function generateWhereUniqueInput(model: DMMF.Model): string {
  const fields = model.fields
    .filter((f) => f.kind !== 'object' && (f.isId || f.isUnique))
    .map((f) => `${f.name}?: ${fieldToTsType(f)}`)
  return renderInterface(`${model.name}WhereUniqueInput`, fields)
}

function generateModelClient(model: DMMF.Model): string {
  const urlPath = toUrlPath(model.name)
  const T = model.name

  return `export class ${T}Client {
  #baseUrl: string

  constructor(baseUrl: string) {
    this.#baseUrl = baseUrl
  }

  async findMany(params?: FindManyParams): Promise<${T}[]> {
    const query = params ? \`?\${new URLSearchParams(params as Record<string, string>).toString()}\` : ''
    const response = await fetch(\`\${this.#baseUrl}/${urlPath}\${query}\`)
    if (!response.ok) throw new Error(\`HTTP \${response.status}: \${response.statusText}\`)
    return response.json() as Promise<${T}[]>
  }

  async findUnique(where: ${T}WhereUniqueInput): Promise<${T} | null> {
    const params = new URLSearchParams(where as Record<string, string>).toString()
    const response = await fetch(\`\${this.#baseUrl}/${urlPath}/unique?\${params}\`)
    if (!response.ok) {
      if (response.status === 404) return null
      throw new Error(\`HTTP \${response.status}: \${response.statusText}\`)
    }
    return response.json() as Promise<${T}>
  }

  async create(data: ${T}CreateInput): Promise<${T}> {
    const response = await fetch(\`\${this.#baseUrl}/${urlPath}\`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    if (!response.ok) throw new Error(\`HTTP \${response.status}: \${response.statusText}\`)
    return response.json() as Promise<${T}>
  }

  async update(where: ${T}WhereUniqueInput, data: ${T}UpdateInput): Promise<${T}> {
    const params = new URLSearchParams(where as Record<string, string>).toString()
    const response = await fetch(\`\${this.#baseUrl}/${urlPath}?\${params}\`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    if (!response.ok) throw new Error(\`HTTP \${response.status}: \${response.statusText}\`)
    return response.json() as Promise<${T}>
  }

  async delete(where: ${T}WhereUniqueInput): Promise<${T}> {
    const params = new URLSearchParams(where as Record<string, string>).toString()
    const response = await fetch(\`\${this.#baseUrl}/${urlPath}?\${params}\`, {
      method: 'DELETE',
    })
    if (!response.ok) throw new Error(\`HTTP \${response.status}: \${response.statusText}\`)
    return response.json() as Promise<${T}>
  }
}`
}

function generateMainClient(models: readonly DMMF.Model[]): string {
  const propertyLines = models.map((m) => `readonly ${toCamelCase(m.name)}: ${m.name}Client`)
  const assignmentLines = models.map((m) => `this.${toCamelCase(m.name)} = new ${m.name}Client(baseUrl)`)

  const body = [
    indent(propertyLines.join('\n'), 2),
    '',
    '  constructor(baseUrl: string) {',
    indent(assignmentLines.join('\n'), 4),
    '  }',
  ].join('\n')

  return `export class RestClient {\n${body}\n}`
}

function generateEnumDeclaration(enumDef: DMMF.DatamodelEnum): string {
  const members = enumDef.values.map((v) => `  ${v.name} = '${v.name}',`).join('\n')
  return `export enum ${enumDef.name} {\n${members}\n}`
}

/**
 * Generates the full content of `rest-client.ts` from the given DMMF document.
 */
export function generateFileContent(dmmf: DMMF.Document): string {
  const { models, enums } = dmmf.datamodel

  const sections: string[] = [
    '// Generated by @prisma/generator-rest-client',
    '// Do not edit this file manually.',
    '',
    'export interface FindManyParams {',
    '  skip?: number',
    '  take?: number',
    '}',
  ]

  for (const enumDef of enums) {
    sections.push('', generateEnumDeclaration(enumDef))
  }

  for (const model of models) {
    sections.push(
      '',
      generateModelInterface(model),
      '',
      generateCreateInput(model),
      '',
      generateUpdateInput(model),
      '',
      generateWhereUniqueInput(model),
      '',
      generateModelClient(model),
    )
  }

  if (models.length > 0) {
    sections.push('', generateMainClient(models))
  }

  return sections.join('\n') + '\n'
}

function resolveOutputPath(options: GeneratorOptions): string {
  const { output } = options.generator
  if (!output) {
    throw new Error('@prisma/generator-rest-client requires an output path')
  }
  if (output.fromEnvVar) {
    const envValue = process.env[output.fromEnvVar]
    if (!envValue) {
      throw new Error(`Environment variable "${output.fromEnvVar}" is not set`)
    }
    return envValue
  }
  return output.value!
}

/**
 * Reads DMMF from `options` and writes `rest-client.ts` to the configured output directory.
 */
export async function generate(options: GeneratorOptions): Promise<void> {
  const outputDir = resolveOutputPath(options)
  const content = generateFileContent(options.dmmf)
  const outputFile = path.join(outputDir, 'rest-client.ts')

  await rm(outputDir, { recursive: true, force: true })
  await mkdir(outputDir, { recursive: true })
  await writeFile(outputFile, content, 'utf-8')
}

